from typing import List, Any

def dedup_by_instant(events: List[Any]) -> List[Any]:
    seen_instants = set()
    result = []

    for event in events:
        if isinstance(event, datetime):
            instant = event.astimezone(timezone.utc).replace(tzinfo=None)
        else:
            instant = event

        if instant not in seen_instants:
            seen_instants.add(instant)
            result.append(event)

    return result
