from zoneinfo import ZoneInfo

def make_local(year, month, day, hour, minute, zone):
    tz = ZoneInfo(zone)
    try:
        return tz.localize(datetime(year, month, day, hour, minute))
    except ValueError:
        # Handle the case where the clocks fell back
        # Return the earlier occurrence
        naive_dt = datetime(year, month, day, hour, minute)
        for offset in tz.utcoffset(naive_dt).possible_utcoffsets():
            try:
                return tz.localize(naive_dt, offset=offset)
            except ValueError:
                continue
        raise ValueError("Invalid date/time")
